import { Component, Input } from '@angular/core';
import { ProductService } from '../product.service';
import { Product } from '../Model';

@Component({
  selector: 'product-form',
  templateUrl: './product-form.component.html',
  styleUrls: ['./product-form.component.css']
})
export class ProductFormComponent {

  @Input() products: Product[];

  constructor(private productService: ProductService){
    this.products=[];
  }

  addProduct(name: string, price: string, isactive:boolean)
  {
    const p = new Product(0,name,Number.parseInt(price),isactive);
    this.productService.addProduct(p)
                                   .subscribe(product=>{
                                    this.products.push(product);
                                   });
  }
}
<div>
  <div class="form-group">
    <label for="name">name</label>
    <input #name type="text" class="form-control" name="name">
    <!-- burada verdiğimiz #name sayesinde girilen input değerine istediğimiz yerden ulaşabiliriz -->
  </div>
  <div class="form-group">
    <label for="price">price</label>
    <input #price type="text" class="form-control" name="price">
  </div>
  <div class="form-group">
    <div class="custom-control custom-checkbox">
      <input #isactive type="checkbox" class="custom-control-input" id="isActive">
      <label for="" class="custom-control-label" for="isActive"></label>
    </div>
  </div>
  <button class="btn btn-primary" (click)="addProduct(name.value,price.value,isactive.checked); name.value=''; price.value=''; isactive.checked=false;">Save Product</button>
</div>
